head.script:
/*년월 setting*/
scwin.strCurYyMm = $c.date.getServerDateTime("yyyyMM");  // 서버를 기준으로 현재 날짜 반환

/*사업자번호*/
scwin.crn = "";
/* 수탁자 매입거래처/수탁자 기준 조회 유형 구분 */
scwin.retrieveType = "";

/*global sesstion정보 */

// 회원정보를 json 데이터로 모두 받음
scwin.userId = $c.data.getMemInfo("userId");
scwin.empNo = $c.data.getMemInfo("empNo");

//alert(scwin.userId + ", " + scwin.empNo);

scwin.f_changeRadioVal = function (inputClsCd) {
    // 01: 수탁자 매입거래처 / 02: 수탁자 기준
    if (inputClsCd == "01") {
        udc_topGrBtn.setGridId("gr_trusteeClntCost");
        udc_bottomGrdBtn.setGridId("gr_trusteeClntCost");

        /*차량번호 팝업 숨김*/
        cartitle.visible(false);
        carlabel.visible(false);

        td_clnt_title.setValue("매입거래처");
        grid_title.setValue("수탁자 매입거래처 기준");

        gr_trusteeClntCost.setStyle("display", "");
        gr_trusteeCost.setStyle("display", "none"); // 그리드 숨기기

        udc_comCode_clnt.show(); // 수탁자 매입거래처 보여주기
        udc_comCode_crn.hide(); //수탁자기준 udc 숨기기
    }
    else if (inputClsCd == "02") {
        udc_topGrBtn.setGridId("gr_trusteeCost");
        udc_bottomGrdBtn.setGridId("gr_trusteeCost");

        cartitle.visible(true);
        carlabel.visible(true);
        td_clnt_title.setValue("매입거래처 수탁자");
        grid_title.setValue("수탁자 기준");

        gr_trusteeClntCost.setStyle("display", "none"); // 그리드 숨기기
        gr_trusteeCost.setStyle("display", ""); // 그리드 보이기

        udc_comCode_clnt.hide(); // 수탁자 매입거래처 udc
        udc_comCode_crn.show(); //수탁자기준 udc
    }
}

scwin.onpageload = function () {
    // 매입거래처 수탁자 기준 조회
    let params = $c.data.getParameter();

    let outbrCo = params.outbrCo == null ? "" : params.outbrCo;
    let outbrNo = params.outbrNo == null ? "" : params.outbrNo;
    let vehclNo = params.vehclNo == null ? "" : params.vehclNo;
    let vehclNm = params.vehclNm == null ? "" : params.vehclNm;
    let regBran = params.regBran == null ? "" : params.regBran;
    let regBranCd = params.regBranCd == null ? "" : params.regBranCd;

    scwin.retrieveType = params.type == null ? "" : request.type;

    // type="retrieve" : 다른 페이지에서 넘어온 데이터 포함 조회(수탁자 기준 조회)
    if (scwin.retrieveType === "retrieve") {
        // 수탁자 기준
        scwin.f_changeRadioVal("02");

        // 파라미터 값 셋팅
        ed_lobranCd.setValue(regBranCd); // 청구지점
        ed_lobranNm.setValue(regBran);

        ed_vehclShortCd.setValue(vehclNo); // 차량번호
        ed_vehclNo.setValue(vehclNm);

        ed_clntNo.setValue(outbrCo); // 매입거래처 수탁자
        ed_clntNm.setValue(outbrNo);
        ed_ctrtDtMm.setValue(scwin.strCurYyMm);

    }
    else {
        // 수탁자 매입거래처
        scwin.f_changeRadioVal("01");
        $c.gus.cfDisableBtnOnly([btn_save]);
    }

    //공통코드 적용
    const codeOptions = [
        { grpCd: "FS900", compID: "gr_trusteeCost:costItemCd, gr_trusteeClntCost:costItemCd" }
    ];

    $c.data.setCommonCode(codeOptions);

    scwin.init();

    // 달력 버튼 포커스 방지
    setTimeout(function () {
        document.querySelectorAll('.w2inputCalendar_div_img button').forEach(function (btn) {
            btn.tabIndex = -1;
        });
    }, 0);

};

scwin.onUdcCompleted = function () {
}

scwin.init = function () {

    ed_ctrtDtMm.setValue(scwin.strCurYyMm); //기준월

    if (rd_inputClsCd.getValue() === "02") {

        scwin.f_vechlPop(function () {
            scwin.f_Retrieve(); //조회 TODO => 차량번호 pop 이후 재 테스트
        }); //차량번호 popup 이후 자동조회       

    } else {
        ed_ctrtDtMm.setValue(scwin.strCurYyMm);
        $c.gus.cfDisableBtnOnly([btn_save]);
    }
};

//-------------------------------------------------------------------------
// 조회조건 Clear
//-------------------------------------------------------------------------
scwin.btn_clear_onclick = function () {
    $c.gus.cfInitObjects(tbl_search, [rd_inputClsCd]);
    ed_ctrtDtMm.setValue(scwin.strCurYyMm); //현재날짜
};

//-------------------------------------------------------------------------
// 입력구분 변경시 Clear
//-------------------------------------------------------------------------
scwin.f_rdChangeClear = function () {
    $c.gus.cfInitObjects(tbl_search, [ed_lobranCd, ed_lobranNm, ed_ctrtDtMm, rd_inputClsCd]);
    /*dslist 초기화*/
    ds_TrusteeCost.removeAll();
    ds_TrusteeCost2.removeAll();
    dma_queryCondition.setEmptyValue();
    scwin.crn = "";

    $c.gus.cfDisableBtnOnly([btn_save]);
    total.setValue("0");
}
scwin.rd_inputClsCd_onchange = function (info) {
    scwin.f_rdChangeClear(); // 입력구분 변경시 데이터 Clear   
    scwin.f_changeRadioVal(rd_inputClsCd.getValue());
};

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
    var inputClsCd = rd_inputClsCd.getValue();

    if (!inputClsCd) return;

    // -----------------------------------------------
    // 분기별 validation 컴포넌트 + submission 정의
    // -----------------------------------------------
    var config = {
        "01": {
            validateTargets: [ed_lobranCd, ed_ctrtDtMm, ed_clntNo],
            sbm: sbm_trusteePurchaseCustomer,
            extraSetting: function () {
                dma_queryCondition.set("crn", scwin.crn.trim());
                dma_queryCondition.set("clntNm", ed_clntNm.getValue());
            }
        },
        "02": {
            validateTargets: [ed_lobranCd, ed_ctrtDtMm, ed_vehclShortCd, ed_crn],
            sbm: sbm_trustee,
            extraSetting: function () {
                dma_queryCondition.set("crn", scwin.crn.trim());
                dma_queryCondition.set("clntNm", ed_crnNm.getValue());
            }
        }
    };

    var cfg = config[inputClsCd];
    if (!cfg) return;

    // -----------------------------------------------
    // validation
    // -----------------------------------------------
    var chkValidate = await $c.gus.cfValidate(cfg.validateTargets);
    if (!chkValidate) return;

    // -----------------------------------------------
    // 공통 dataMap setting
    // -----------------------------------------------
    dma_queryCondition.set("lobranCd", ed_lobranCd.getValue());
    dma_queryCondition.set("ctrtDtMm", ed_ctrtDtMm.getValue());
    dma_queryCondition.set("vehclNo", ed_vehclNo.getValue());

    // -----------------------------------------------
    // 분기별 추가 setting
    // -----------------------------------------------
    cfg.extraSetting();

    // -----------------------------------------------
    // submission 실행
    // -----------------------------------------------
    $c.sbm.execute(cfg.sbm);
}

// 조회 버튼 클릭
scwin.btn_search_onclick = async function (e) {
    scwin.f_Retrieve();
};

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_save_onclick = async function (e) {
    var inputClsCd = rd_inputClsCd.getValue();

    // -----------------------------------------------
    // 공통 validation 함수
    // -----------------------------------------------
    async function validateCostData(ds, gr, sbm) {

        // 1. 데이터 존재 여부
        if (ds.getRowCount() < 1) {
            $c.gus.cfAlertMsg(MSG_CM_WRN_003, ["저장할 수탁자 비용내역"]);
            return false;
        }

        // 2. 수정된 데이터 존재 여부
        var modifiedIdx = ds.getModifiedIndex();
        if (modifiedIdx.length === 0) {
            $c.gus.cfAlertMsg(MSG_CM_ERR_001, ["수탁자 비용내역"]);
            return false;
        }

        // 3. 그리드 validation
        let chkValidate = await $c.gus.cfValidate([gr]);
        if (!chkValidate) return false;

        // 4. 과태료 고지번호 필수 체크
        var rowIndex = ds.getRowPosition();
        var costItemCd = ds.getCellData(rowIndex, "costItemCd");
        var ntceNo = ds.getCellData(rowIndex, "ntceNo");

        if (costItemCd === "09" && (ntceNo === "" || ntceNo === null)) {
            $c.gus.cfAlertMsg("비용항목이 과태료일 경우 고지번호는 필수 입력값입니다.");
            return false;
        }

        // 5. 저장 확인
        if (!await $c.win.confirm(MSG_CM_CRM_001)) {
            return false;
        }

        return true;
    }

    // -----------------------------------------------
    // 공통 데이터 가공 함수
    // -----------------------------------------------
    function processCostData(ds, callback) {
        for (var i = 0; i < ds.getRowCount(); i++) {
            // 수정된 행만 oilSubsidyPayStdDt 세팅
            if (ds.getRowStatusValue(i) === 2) {
                ds.setCellData(i, "oilSubsidyPayStdDt", ds.getCellData(i, "calnDocDrawDt"));
            }
        }

        // 2. 전달받은 인자가 함수인지 확인 후 실행
        // 보통 팝업이 닫히거나 특정 작업이 끝난 시점에 실행하게 됩니다.
        if (typeof callback === "function") {
            callback();
        }

    }

    // -----------------------------------------------
    // "01" 수탁자 매입처 기준
    // -----------------------------------------------
    if (inputClsCd === "01") {
        if (!await validateCostData(ds_TrusteeCost, gr_trusteeClntCost, sbm_save1)) return;

        processCostData(ds_TrusteeCost, function () {
            $c.sbm.execute(sbm_save1);
        });
    }

    // -----------------------------------------------
    // "02" 수탁자 기준
    // -----------------------------------------------
    if (inputClsCd === "02") {
        if (!await validateCostData(ds_TrusteeCost2, gr_trusteeCost, sbm_save2)) return;

        processCostData(ds_TrusteeCost2, function () {

            $c.sbm.execute(sbm_save2);
        });
    }
};

//차량번호
scwin.udc_comCode_vehcl_onclickEvent = async function (e) {
    //변경처리(비동기 방식)
    scwin.f_vechlPop();

};

//-------------------------------------------------------------------------
// 사업자번호 팝업
//-------------------------------------------------------------------------
scwin.f_crnPop = async function () {
    if (rd_inputClsCd.getValue() == "02") return;

    var data = {
        param1: ed_clntNo.getValue().trim(),			// 매입거래처 코드
        param2: ed_clntNm.getValue()					// 매입거래처 이름
    };

    var opts = {
        id: "searchpop",
        popupName: "수탁자 매입거래처 조회 팝업",
        modal: true,
        type: "",
        width: 800,      // 가로 크기 (픽셀)
        height: 600,     // 세로 크기 (픽셀)
        title: "Win pop"
    };

    let rtnList = await $c.win.openPopup("/ui/ds/fs/consignmgnt/fs_402_01_05p.xml", opts, data);
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm, ed_costItemCd, ed_costItemNm, ed_crn);    //매입처코드,명

    var busiNo = rtnList ? rtnList[0] : ""; // 사업자 번호 
    var clntNo = rtnList ? rtnList[1] : ""; // 매입거래처 번호
    var clntNm = rtnList ? rtnList[2] : ""; // 매입거래처명
    var costItemCd = rtnList ? rtnList[3] : ""; // 비용구분 코드
    var costItemNm = rtnList ? rtnList[4] : ""; // 비용명 

    scwin.crn = busiNo;
    ed_clntNo.setValue(clntNo);
    ed_clntNm.setValue(clntNm);
    ed_costItemCd.setValue(costItemCd);
    ed_costItemNm.setValue(costItemNm);
}

//-------------------------------------------------------------------------
// 차량번호 팝업
//-------------------------------------------------------------------------
scwin.f_vechlPop = async function (callback) {

    if (!$c.gus.cfValidate([ed_ctrtDtMm]))
        return;

    let obj = {
        param1: ed_ctrtDtMm.getValue(),
        param2: ed_vehclShortCd.getValue(),  // 차량 단축 코드
        param3: ed_vehclNo.getValue() // 차량 번호 이름
    }

    // 팝업 옵션 설정
    let options = {
        id: "searchpop",
        type: "",
        popupName: "수탁자 차량 계약정보 조회 팝업",
        width: 800,
        height: 550
    };

    //상세화면 호출
    rtnList = await $c.win.openPopup("/ui/ds/fs/consignmgnt/fs_402_01_04p.xml", options, obj);
    $c.gus.cfSetReturnValue(rtnList);

    //결과값 (udc 정리후 retest)
    //차량번호 조회 팝업 결과값 
    let ctrtDtMn = rtnList ? rtnList.ctrtDtMm : "";

    scwin.crn = rtnList ? rtnList.crn : ""; // 사업자 번호

    if (!$c.util.isEmpty(ctrtDtMn)) ed_ctrtDtMm.setValue(ctrtDtMn); // 차량조회 팝업에서 조회한 연월
    ed_crn.setValue(rtnList ? rtnList.clntNo : "");
    ed_crnNm.setValue(rtnList ? rtnList.clntNm : "");
    ed_vehclNo.setValue(rtnList ? rtnList.vehclNo : "");
    ed_vehclShortCd.setValue(rtnList ? rtnList.vehclShortCd : "");
    ed_costItemCd.setValue(rtnList ? rtnList.costItemCd : "");
    // ed_costItemNm.setValue(rtnList ? rtnList.costItemNm : "");

    ed_eqCd.setValue(rtnList ? rtnList.eqCd : "");
    ed_ctrtNo.setValue(rtnList ? rtnList.ctrtNo : "");

    // 팝업이 닫힐 때 실행되는 내부 콜백
    if (typeof callback === "function") {
        callback(); // 넘겨받은 f_Retrieve() 등이 여기서 실행됨
    }
};

//-------------------------------------------------------------------------
// 그리드의 사업자번호 PopUp
//-------------------------------------------------------------------------	
scwin.f_gridCrnPop = async function (rowIndex) {
    if (scwin.isNonPop) {
        scwin.isNonPop = false;
        return;
    }

    var data = {
        param1: ds_TrusteeCost2.getCellData(rowIndex, "clntNo"),			// 매입거래처 코드
        param2: ds_TrusteeCost2.getCellData(rowIndex, "clntNm").trim(),			// 매입거래처 이름
        param3: ds_TrusteeCost2.getCellData(rowIndex, "crn")                // 사업자번호
    };

    var opts = {
        id: "searchpop",
        popupName: "수탁자 매입거래처 조회 팝업",
        modal: true,
        type: "",
        width: 800,      // 가로 크기 (픽셀)
        height: 600,     // 세로 크기 (픽셀)
        title: "Win pop"
    };

    let rtnList = await $c.win.openPopup("/ui/ds/fs/consignmgnt/fs_402_01_05p.xml", opts, data);
    $c.gus.cfSetReturnValue(rtnList, ed_clntNo, ed_clntNm, ed_costItemCd, ed_costItemNm, ed_crn);    //매입처코드,명

    var busiNo = rtnList ? rtnList[0] : ""; // 사업자 번호 
    var clntNo = rtnList ? rtnList[1] : ""; // 매입거래처 번호
    var clntNm = rtnList ? rtnList[2] : ""; // 매입거래처명
    var costItemCd = rtnList ? rtnList[3] : ""; // 비용구분 코드
    var costItemNm = rtnList ? rtnList[4] : ""; // 비용명 

    // 사업자번호, 거래처번호, 상호, 비용항목
    ds_TrusteeCost2.setCellData(rowIndex, "crn", busiNo);
    ds_TrusteeCost2.setCellData(rowIndex, "clntNo", clntNo);
    ds_TrusteeCost2.setCellData(rowIndex, "clntNm", clntNm);
    if (!$c.util.isEmpty(clntNo)) {
        ds_TrusteeCost2.setCellData(rowIndex, "costItemCd", ed_costItemCd.getValue());
    } else {
        ds_TrusteeCost2.setCellData(rowIndex, "costItemCd", "");
    }
}


// 청구지점 팝업 호출
scwin.udc_comCode_lobran_onclickEvent = async function (e) {

    scwin.f_openCommonPopUp(1, ed_lobranCd.getValue(), ed_lobranNm.getValue(), "F", "F");
};

// 청구지점 팝업 CallBack
scwin.udc_comCode_lobran_callBackFunc = function (ret) {

    $c.gus.cfSetReturnValue(ret, ed_lobranCd, ed_lobranNm);
};


//비용구분
scwin.ed_costItemCd_onchange = function (info) {

    if (ed_costItemCd.getValue() !== "") {

        if (ds_cost.getRowCount() > 0) {
            let indices = ds_cost.getMatchedIndex("costItemCd", ed_costItemCd.getValue());
            ed_costItemNm.setValue(ds_cost.getCellData(indices, "costItemNm"));
        } else {
            dma_costItem.set("pCode", ed_costItemCd.getValue());
            $c.sbm.execute(sbm_costitem);
        }
    }
};

//수탁자 매입거래처 > 수탁자 매입거래처 조회 팝업
scwin.udc_comCode_clnt_onclickEvent = async (e) => scwin.f_crnPop();

//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = async function (disGubun, pCode, pName, pClose, pAllSearch) {
    switch (disGubun) {
        case 1:
            // 청구지점 공통 팝업
            udc_comCode_lobran.setSelectId("retrieveLobranInfo");
            await udc_comCode_lobran.cfCommonPopUp(
                scwin.udc_comCode_lobran_callBackFunc,
                pCode.trim(),
                pName,
                pClose,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                null,
                pAllSearch,
                null);

            break;

        case 2:
            // 수탁자 기준 >> 매입거래처 수탁자 조회 (공통 팝업)
            udc_comCode_crn.setSelectId("");
            await udc_comCode_crn.cfCommonPopUp(
                scwin.udc_comCode_crn_callBackFunc,
                pCode.trim(),
                pName,
                pClose,
                null, null, null, null, null, null, null, null, null, null,
                pAllSearch,
                null);
            break;

        default:
            break;
    }
};

//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopup = function (inObj, pairObj, disGubun, isCode) {
    // 수탁자 매입거래처 기준일때의 Popup
    if (disGubun == 2 && rd_inputClsCd.getValue() === "01") {
        scwin.f_crnPop("clntNm");
        return;
    }

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 셋팅
    var pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true) {
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
        // inObj가 코드명 필드일 경우 팝업
    } else {
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');
    }
}

//수탁자 매입거래처 조회 callback 
scwin.sbm_trusteePurchaseCustomer_submintdone = async function () {
    if (ds_TrusteeCost.getTotalRow() == 0) {
        if (await $c.gus.cfAlertMsg(MSG_CM_WRN_002)) {
            scwin.f_AddRowAfterRetrieve();
        }
    }

    // 그리드 첫째 행 index선택
    gr_trusteeClntCost.setFocusedCell(0, 0);
    let nCnt = ds_TrusteeCost.getRowCount();
    total.setValue(nCnt);

    $c.gus.cfEnableBtnOnly([btn_save]);
}

//수탁자 기준 조회 callback 
scwin.sbm_trustee_submintdone = async function () {
    if (ds_TrusteeCost2.getTotalRow() == 0) {
        if (await $c.gus.cfAlertMsg(MSG_CM_WRN_002)) {
            scwin.f_AddRowAfterRetrieve();
        }
    }

    // 그리드 첫째 행 index선택
    gr_trusteeCost.setFocusedCell(0, 0);
    let nCnt = ds_TrusteeCost2.getRowCount();
    total.setValue(nCnt);

    $c.gus.cfEnableBtnOnly([btn_save]);
}

// -----------------------------------------------
// 분기별 config 공통 함수
// -----------------------------------------------
scwin.f_getConfig = function () {

    var inputClsCd = rd_inputClsCd.getValue();

    var config = {
        "01": {
            ds: ds_TrusteeCost,
            clearDs: ds_TrusteeCost2,
            gr: gr_trusteeClntCost,
            fields: {
                lobranCd: dma_queryCondition.get("lobranCd"),
                clntNo: ed_clntNo.getValue(),
                crn: dma_queryCondition.get("crn"),
                clntNm: dma_queryCondition.get("clntNm"),
                costItemCd: ed_costItemCd.getValue(),
                costItemNm: ed_costItemNm.getValue(),
                taxnClsCd: "1"
            }
        },
        "02": {
            ds: ds_TrusteeCost2,
            clearDs: ds_TrusteeCost,
            gr: gr_trusteeCost,
            fields: {
                lobranCd: dma_queryCondition.get("lobranCd"),
                vehclShortCd: ed_vehclShortCd.getValue(),
                vehclNo: dma_queryCondition.get("vehclNo"),
                ctrtNo: ed_ctrtNo.getValue(),
                eqCd: ed_eqCd.getValue(),
                costItemCd: ed_costItemCd.getValue(),
                costItemNm: ed_costItemNm.getValue(),
                taxnClsCd: "1"
            }
        }
    };

    return config[inputClsCd] || null;
};

// -----------------------------------------------
// 행 추가 (공통)
// -----------------------------------------------
scwin.f_insertRow = function (cfg) {

    var nRow = cfg.ds.getRowCount();

    cfg.ds.insertRow(nRow);

    Object.keys(cfg.fields).forEach(function (key) {
        cfg.ds.setCellData(nRow, key, cfg.fields[key]);
    });

    cfg.gr.setFocusedCell(nRow, 0);
};

// -----------------------------------------------
// 행 추가 버튼 클릭 - 조회 후 행 추가
// -----------------------------------------------
scwin.f_AddRow = function () {

    var cfg = scwin.f_getConfig();
    if (!cfg) return;

    // 조회 여부 체크
    if (cfg.ds.getRowCount() < 1) {
        $c.gus.cfAlertMsg("조회후에 저장이 가능합니다.");
        return;
    }

    cfg.clearDs.removeAll();
    scwin.f_insertRow(cfg);
};

// -----------------------------------------------
// 최초 조회 후 데이터 없을 때 자동 행 추가
// -----------------------------------------------
scwin.f_AddRowAfterRetrieve = function () {

    var cfg = scwin.f_getConfig();
    if (!cfg) return;

    // 데이터 없을 때만 행 추가
    if (cfg.ds.getRowCount() < 1) {
        cfg.clearDs.removeAll();
        scwin.f_insertRow(cfg);
    }
};

//-------------------------------------------------------------------------
// 그리드 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {

    if (rd_inputClsCd.getValue() === "01") {
        $c.data.undoRow(ds_TrusteeCost, "Y");
    } else {
        $c.data.undoRow(ds_TrusteeCost2, "Y");
    }
};

//-------------------------------------------------------------------------
// 그리드 삭제
//-------------------------------------------------------------------------
scwin.f_DelRow = function () {
    var inputClsCd = rd_inputClsCd.getValue();

    // 분기별 그리드 / DataList 설정
    var gr = inputClsCd === "01" ? gr_trusteeClntCost : gr_trusteeCost;
    var ds = inputClsCd === "01" ? ds_TrusteeCost : ds_TrusteeCost2;

    // 포커스된 행 인덱스
    var focusedIdx = gr.getFocusedRowIndex();
    if (focusedIdx === -1) {
        return;
    }

    // 신규행(I)이면 바로 제거, 기존행이면 D 상태로 변경
    if (ds.getRowStatus(focusedIdx) === "I") {
        $c.data.undoRow(ds, "Y");
    } else {
        $c.data.undoRow(ds, "Y");
        $c.data.deleteRow(ds, focusedIdx);
    }
}

